"use client";

import { useSession, signOut } from "next-auth/react";
import { useState, useEffect } from "react";
import { redirect } from "next/navigation";

/**
 * ระบบจัดการโปรไฟล์ผู้ใช้งานระดับสากล (Universal Profile Management)
 * รองรับการอัปโหลดรูปภาพและการแก้ไขข้อมูลส่วนบุคคล
 */
export default function ProfilePage() {
  const { data: session, status, update } = useSession();
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  
  const [formData, setFormData] = useState({
    name: "",
    image: ""
  });

  useEffect(() => {
    if (session?.user) {
      setFormData({
        name: session.user.name || "",
        image: session.user.image || ""
      });
    }
  }, [session]);

  if (status === "unauthenticated") redirect("/login");

  // ระบบอัปโหลดรูปภาพและประมวลผลเป็น Base64
  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1024 * 1024) { // จำกัดขนาด 1MB เพื่อประสิทธิภาพ
        alert("ขนาดไฟล์ภาพใหญ่เกินกว่าที่กำหนด (จำกัดที่ 1MB ค่ะ)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({ ...formData, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      // ส่งข้อมูลไปอัปเดต Session ของ NextAuth
      await update({
        ...session,
        user: { ...session?.user, name: formData.name, image: formData.image }
      });
      
      setIsEditing(false);
      alert("ระบบบันทึกการเปลี่ยนแปลงเรียบร้อยแล้วค่ะ");
    } catch (error) {
      alert("เกิดข้อผิดพลาดในการบันทึกข้อมูล กรุณาลองใหม่อีกครั้ง");
    } finally {
      setIsSaving(false);
    }
  };

  if (status === "loading") return <div style={centerStyle}>กำลังเข้าสู่ระบบจัดการโปรไฟล์...</div>;

  return (
    <main style={containerStyle}>
      <header style={headerStyle}>
        <h1 style={titleStyle}>การตั้งค่าโปรไฟล์</h1>
        <p style={subtitleStyle}>จัดการข้อมูลบัญชีและรูปภาพประจำตัวสำหรับผู้ใช้งาน Medi-Tap</p>
      </header>

      <div style={cardStyle}>
        {/* ส่วนอัปโหลดรูปภาพโปรไฟล์ (Avatar Management) */}
        <section style={avatarUploadSection}>
          <div style={avatarPreview}>
            {formData.image ? (
              <img src={formData.image} alt="Profile" style={imgStyle} />
            ) : (
              <div style={avatarPlaceholder}>{formData.name?.[0] || "U"}</div>
            )}
          </div>
          {isEditing && (
            <div style={uploadTrigger}>
              <label htmlFor="imageUpload" style={uploadLabel}>อัปโหลดรูปภาพใหม่</label>
              <input 
                id="imageUpload" 
                type="file" 
                accept="image/*" 
                onChange={handleImageChange} 
                style={{ display: 'none' }} 
              />
            </div>
          )}
        </section>

        {/* ฟอร์มข้อมูลผู้ใช้งาน (User Information Form) */}
        <div style={formGrid}>
          <div style={inputGroup}>
            <label style={fieldLabel}>ชื่อที่แสดงผล (Display Name)</label>
            <input 
              type="text" 
              placeholder="กรุณาระบุชื่อของท่าน"
              value={formData.name}
              disabled={!isEditing}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              style={isEditing ? inputStyleActive : inputStyle}
            />
          </div>

          <div style={inputGroup}>
            <label style={fieldLabel}>อีเมล (Email Address)</label>
            <input 
              type="email" 
              value={session?.user?.email || ""}
              disabled={true} 
              style={inputStyleDisabled}
            />
            <span style={hintText}>อีเมลไม่สามารถเปลี่ยนแปลงได้เนื่องจากเป็นบัญชีหลัก</span>
          </div>
        </div>

        <div style={divider} />

        {/* ส่วนการดำเนินการ (Actions) */}
        <div style={actionRow}>
          {isEditing ? (
            <>
              <button onClick={() => setIsEditing(false)} style={cancelBtn} disabled={isSaving}>ยกเลิก</button>
              <button onClick={handleSave} style={saveBtn} disabled={isSaving}>
                {isSaving ? "กำลังบันทึก..." : "บันทึกการเปลี่ยนแปลง"}
              </button>
            </>
          ) : (
            <button onClick={() => setIsEditing(true)} style={editBtn}>แก้ไขข้อมูลโปรไฟล์</button>
          )}
        </div>
      </div>
      
      <button onClick={() => signOut({ callbackUrl: "/" })} style={logoutBtn}>ออกจากระบบ</button>
    </main>
  );
}

// --- Enterprise Public Styles ---
const containerStyle = { maxWidth: '700px', margin: '0 auto', padding: '60px 24px' };
const headerStyle = { marginBottom: '40px', textAlign: 'center' as const };
const titleStyle = { fontSize: '32px', fontWeight: '900', color: '#0f172a', letterSpacing: '-0.5px' };
const subtitleStyle = { fontSize: '16px', color: '#64748b', marginTop: '10px' };

const cardStyle = { background: '#fff', padding: '48px', borderRadius: '32px', border: '1px solid #f1f5f9', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.04)' };

const avatarUploadSection = { display: 'flex', flexDirection: 'column' as const, alignItems: 'center', marginBottom: '40px' };
const avatarPreview = { width: '130px', height: '130px', borderRadius: '50%', overflow: 'hidden', background: '#0ea5e9', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '4px solid #fff', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' as const };
const avatarPlaceholder = { fontSize: '52px', color: '#fff', fontWeight: '800' };
const uploadTrigger = { marginTop: '16px' };
const uploadLabel = { fontSize: '15px', fontWeight: '700', color: '#0ea5e9', cursor: 'pointer', textDecoration: 'underline' };

const formGrid = { display: 'grid', gap: '28px' };
const inputGroup = { display: 'flex', flexDirection: 'column' as const, gap: '10px' };
const fieldLabel = { fontSize: '15px', fontWeight: '800', color: '#1e293b' };
const inputStyle = { padding: '14px 18px', borderRadius: '14px', border: '1px solid #e2e8f0', background: '#ffffff', fontSize: '16px', color: '#1e293b', transition: 'all 0.2s', outline: 'none' };
const inputStyleActive = { ...inputStyle, borderColor: '#0ea5e9', boxShadow: '0 0 0 4px rgba(14, 165, 233, 0.1)' };
const inputStyleDisabled = { ...inputStyle, background: '#f8fafc', color: '#94a3b8', cursor: 'not-allowed' };
const hintText = { fontSize: '12px', color: '#94a3b8', marginTop: '2px' };

const divider = { height: '1px', background: '#f1f5f9', margin: '40px 0' };

const actionRow = { display: 'flex', gap: '14px', justifyContent: 'flex-end' };
const editBtn = { padding: '14px 28px', borderRadius: '14px', background: '#0f172a', color: '#fff', border: 'none', fontWeight: '700', cursor: 'pointer', fontSize: '15px' };
const saveBtn = { ...editBtn, background: '#0ea5e9' };
const cancelBtn = { padding: '14px 28px', borderRadius: '14px', background: '#fff', color: '#64748b', border: '1px solid #e2e8f0', fontWeight: '700', cursor: 'pointer', fontSize: '15px' };

const logoutBtn = { width: '100%', marginTop: '32px', padding: '16px', borderRadius: '16px', border: 'none', background: '#fff', color: '#ef4444', fontWeight: '800', cursor: 'pointer', border: '1px solid #fee2e2' };
const centerStyle = { textAlign: 'center' as const, padding: '100px', color: '#64748b' };